Here's a complete conversion of your raindrop shader from Standard Renderer to Universal Renderer Pipeline (URP):

```hlsl
Shader "URP/Custom/RaindropFX/WetSurfaceGrab"
{
    Properties
    {
        _BumpAmt("Distortion", range(0,32)) = 10
        _IOR("IOR", range(0,1)) = 0.1
        _BumpDetailAmt("DetailDistortion", range(0,1)) = 0.5
        _TintAmt("Tint Amount", Range(0,1)) = 0.1
        _Roughness("Roughness", Range(0,30)) = 1.0
        _RoughIter("RoughIteration", Range(0.01,10)) = 0.2
        _Reflect("Reflect", Range(0,1)) = 0.3
        _FogAmt("Fog", Range(0,1)) = 0
        _FogItr("FogIteration", Range(0,10)) = 1
        _FogCol("FogColor", Color) = (1, 1, 1, 1)

        _MainTex("TintColor(RGB)", 2D) = "white" {}
        _BumpMap("NormalMap", 2D) = "bump" {}
        _FogMaskMap("WetMap", 2D) = "white" {}
        _Cube("Enviroment", Cube) = "_Skybox"{}
    }

    SubShader
    {
        Tags 
        { 
            "Queue" = "Transparent" 
            "IgnoreProjector" = "True" 
            "RenderType" = "Transparent"
            "RenderPipeline" = "UniversalPipeline"
        }

        // In URP, we need to use _CameraOpaqueTexture instead of GrabPass
        // This requires setting up the Opaque Texture in URP settings

        // Horizontal blur pass
        Pass
        {
            Name "HorizontalBlur"
            Tags { "LightMode" = "UniversalForward" }

            Blend SrcAlpha OneMinusSrcAlpha
            ZWrite Off
            Cull Off

            HLSLPROGRAM
            #pragma vertex vert
            #pragma fragment frag
            #pragma multi_compile_fog

            #include "Packages/com.unity.render-pipelines.universal/ShaderLibrary/Core.hlsl"
            #include "Packages/com.unity.render-pipelines.universal/ShaderLibrary/DeclareOpaqueTexture.hlsl"

            TEXTURE2D(_FogMaskMap);
            SAMPLER(sampler_FogMaskMap);

            float _Roughness;
            float _RoughIter;

            struct Attributes
            {
                float4 positionOS : POSITION;
                float2 texcoord : TEXCOORD0;
            };

            struct Varyings
            {
                float4 positionCS : SV_POSITION;
                float4 screenPos : TEXCOORD0;
                float2 uv : TEXCOORD1;
            };

            Varyings vert(Attributes input)
            {
                Varyings output;
                output.positionCS = TransformObjectToHClip(input.positionOS.xyz);
                output.uv = input.texcoord;

                // Calculate screen position for sampling _CameraOpaqueTexture
                output.screenPos = ComputeScreenPos(output.positionCS);
                return output;
            }

            half4 frag(Varyings input) : SV_Target
            {
                float2 screenUV = input.screenPos.xy / input.screenPos.w;

                // Sample _CameraOpaqueTexture (URP's replacement for GrabPass)
                float2 texelSize = float2(1.0 / _ScreenParams.x, 1.0 / _ScreenParams.y);

                #define SAMPLE_SCENE_TEXTURE(offset) SampleSceneColor(screenUV + offset)

                half4 sum = half4(0, 0, 0, 0);
                sum += SAMPLE_SCENE_TEXTURE(float2(-4.0 * texelSize.x * _Roughness, 0)) * 0.05;
                sum += SAMPLE_SCENE_TEXTURE(float2(-3.0 * texelSize.x * _Roughness, 0)) * 0.09;
                sum += SAMPLE_SCENE_TEXTURE(float2(-2.0 * texelSize.x * _Roughness, 0)) * 0.12;
                sum += SAMPLE_SCENE_TEXTURE(float2(-1.0 * texelSize.x * _Roughness, 0)) * 0.15;
                sum += SAMPLE_SCENE_TEXTURE(float2(0, 0)) * 0.18;
                sum += SAMPLE_SCENE_TEXTURE(float2(1.0 * texelSize.x * _Roughness, 0)) * 0.15;
                sum += SAMPLE_SCENE_TEXTURE(float2(2.0 * texelSize.x * _Roughness, 0)) * 0.12;
                sum += SAMPLE_SCENE_TEXTURE(float2(3.0 * texelSize.x * _Roughness, 0)) * 0.09;
                sum += SAMPLE_SCENE_TEXTURE(float2(4.0 * texelSize.x * _Roughness, 0)) * 0.05;

                float fogMask = SAMPLE_TEXTURE2D(_FogMaskMap, sampler_FogMaskMap, input.uv).r;
                half4 col = SAMPLE_SCENE_TEXTURE(float2(0, 0));
                sum = lerp(sum, col, clamp(pow(fogMask, 1.0 / _RoughIter) * 10.0, 0, 1));

                return sum;
            }
            ENDHLSL
        }

        // Vertical blur pass
        Pass
        {
            Name "VerticalBlur"
            Tags { "LightMode" = "UniversalForward" }

            Blend SrcAlpha OneMinusSrcAlpha
            ZWrite Off
            Cull Off

            HLSLPROGRAM
            #pragma vertex vert
            #pragma fragment frag
            #pragma multi_compile_fog

            #include "Packages/com.unity.render-pipelines.universal/ShaderLibrary/Core.hlsl"
            #include "Packages/com.unity.render-pipelines.universal/ShaderLibrary/DeclareOpaqueTexture.hlsl"

            TEXTURE2D(_FogMaskMap);
            SAMPLER(sampler_FogMaskMap);

            float _Roughness;
            float _RoughIter;

            struct Attributes
            {
                float4 positionOS : POSITION;
                float2 texcoord : TEXCOORD0;
            };

            struct Varyings
            {
                float4 positionCS : SV_POSITION;
                float4 screenPos : TEXCOORD0;
                float2 uv : TEXCOORD1;
            };

            Varyings vert(Attributes input)
            {
                Varyings output;
                output.positionCS = TransformObjectToHClip(input.positionOS.xyz);
                output.uv = input.texcoord;
                output.screenPos = ComputeScreenPos(output.positionCS);
                return output;
            }

            half4 frag(Varyings input) : SV_Target
            {
                float2 screenUV = input.screenPos.xy / input.screenPos.w;
                float2 texelSize = float2(1.0 / _ScreenParams.x, 1.0 / _ScreenParams.y);

                #define SAMPLE_SCENE_TEXTURE(offset) SampleSceneColor(screenUV + offset)

                half4 sum = half4(0, 0, 0, 0);
                sum += SAMPLE_SCENE_TEXTURE(float2(0, -4.0 * texelSize.y * _Roughness)) * 0.05;
                sum += SAMPLE_SCENE_TEXTURE(float2(0, -3.0 * texelSize.y * _Roughness)) * 0.09;
                sum += SAMPLE_SCENE_TEXTURE(float2(0, -2.0 * texelSize.y * _Roughness)) * 0.12;
                sum += SAMPLE_SCENE_TEXTURE(float2(0, -1.0 * texelSize.y * _Roughness)) * 0.15;
                sum += SAMPLE_SCENE_TEXTURE(float2(0, 0)) * 0.18;
                sum += SAMPLE_SCENE_TEXTURE(float2(0, 1.0 * texelSize.y * _Roughness)) * 0.15;
                sum += SAMPLE_SCENE_TEXTURE(float2(0, 2.0 * texelSize.y * _Roughness)) * 0.12;
                sum += SAMPLE_SCENE_TEXTURE(float2(0, 3.0 * texelSize.y * _Roughness)) * 0.09;
                sum += SAMPLE_SCENE_TEXTURE(float2(0, 4.0 * texelSize.y * _Roughness)) * 0.05;

                float fogMask = SAMPLE_TEXTURE2D(_FogMaskMap, sampler_FogMaskMap, input.uv).r;
                half4 col = SAMPLE_SCENE_TEXTURE(float2(0, 0));
                sum = lerp(sum, col, clamp(pow(fogMask, 1.0 / _RoughIter) * 10.0, 0, 1));

                return sum;
            }
            ENDHLSL
        }

        // Distortion pass
        Pass
        {
            Name "Distortion"
            Tags { "LightMode" = "UniversalForward" }

            Blend SrcAlpha OneMinusSrcAlpha
            ZWrite Off
            Cull Off

            HLSLPROGRAM
            #pragma vertex vert
            #pragma fragment frag
            #pragma multi_compile_fog

            #include "Packages/com.unity.render-pipelines.universal/ShaderLibrary/Core.hlsl"
            #include "Packages/com.unity.render-pipelines.universal/ShaderLibrary/Lighting.hlsl"
            #include "Packages/com.unity.render-pipelines.universal/ShaderLibrary/DeclareOpaqueTexture.hlsl"

            float _IOR;
            float _FogAmt;
            float _FogItr;
            float _Reflect;
            float _Roughness;
            float _BumpAmt;
            float _BumpDetailAmt;
            half _TintAmt;
            half4 _FogCol;

            TEXTURE2D(_Cube);
            SAMPLER(sampler_Cube);
            TEXTURE2D(_BumpMap);
            SAMPLER(sampler_BumpMap);
            TEXTURE2D(_MainTex);
            SAMPLER(sampler_MainTex);
            TEXTURE2D(_FogMaskMap);
            SAMPLER(sampler_FogMaskMap);

            float4 _BumpMap_ST;
            float4 _MainTex_ST;

            struct Attributes
            {
                float4 positionOS : POSITION;
                float2 texcoord : TEXCOORD0;
                float3 normalOS : NORMAL;
                float4 tangentOS : TANGENT;
            };

            struct Varyings
            {
                float4 positionCS : SV_POSITION;
                float4 screenPos : TEXCOORD0;
                float2 uvbump : TEXCOORD1;
                float2 uvmain : TEXCOORD2;
                float3 viewDirWS : TEXCOORD3;
                float3 normalWS : TEXCOORD4;
                float3 tangentWS : TEXCOORD5;
                float3 bitangentWS : TEXCOORD6;
            };

            Varyings vert(Attributes input)
            {
                Varyings output;

                VertexPositionInputs vertexInput = GetVertexPositionInputs(input.positionOS.xyz);
                VertexNormalInputs normalInput = GetVertexNormalInputs(input.normalOS, input.tangentOS);

                output.positionCS = vertexInput.positionCS;
                output.screenPos = ComputeScreenPos(output.positionCS);
                output.uvbump = TRANSFORM_TEX(input.texcoord, _BumpMap);
                output.uvmain = TRANSFORM_TEX(input.texcoord, _MainTex);

                output.normalWS = normalInput.normalWS;
                output.tangentWS = normalInput.tangentWS;
                output.bitangentWS = normalInput.bitangentWS;
                output.viewDirWS = GetWorldSpaceNormalizeViewDir(vertexInput.positionWS);

                return output;
            }

            half4 frag(Varyings input) : SV_Target
            {
                float2 screenUV = input.screenPos.xy / input.screenPos.w;

                // Sample textures
                half4 tint = SAMPLE_TEXTURE2D(_MainTex, sampler_MainTex, input.uvmain);
                half3 bump = UnpackNormal(SAMPLE_TEXTURE2D(_BumpMap, sampler_BumpMap, input.uvbump)).rgb;

                // Transform normal to world space
                float3x3 tangentToWorld = float3x3(input.tangentWS, input.bitangentWS, input.normalWS);
                float3 normalWS = mul(bump, tangentToWorld);

                // Calculate distortion offset
                float2 texelSize = float2(1.0 / _ScreenParams.x, 1.0 / _ScreenParams.y);
                float2 offset = bump.xy * _BumpAmt * 10.0 * texelSize + float2(0.05, 0.05) * (tint.r * _BumpDetailAmt + _IOR);

                // Sample scene texture with distortion
                half4 col = SampleSceneColor(screenUV + offset);

                // Reflection
                float fogMask = SAMPLE_TEXTURE2D(_FogMaskMap, sampler_FogMaskMap, input.uvmain).r;
                float3 reflectDir = reflect(-input.viewDirWS, normalWS);
                half4 ref = SAMPLE_TEXTURECUBE(_Cube, sampler_Cube, reflectDir + bump * clamp(fogMask + 0.2, 0, 1) * _BumpAmt);

                // Combine effects
                half4 fcol = lerp(col, ref, _Reflect);
                fcol = lerp(fcol, tint, _TintAmt);
                col = lerp(col, tint, _TintAmt);

                // Fog effect
                half wet = clamp(pow(fogMask, 0.5) * _FogItr, 0, 1);
                col = lerp(col, col * wet + (_FogCol + col * 0.5) * (1.0 - wet), _FogAmt);
                col = lerp(col, ref, _Reflect * clamp(wet * wet, 0, 1));
                col = lerp(col, fcol, 1.0 - clamp(_FogAmt * 5, 0, 1));

                return col;
            }
            ENDHLSL
        }
    }

    FallBack "Universal Render Pipeline/Unlit"
}
```

**Important Setup Notes for URP:**

1. **Enable Opaque Texture**: In your URP Asset settings, go to Renderer → Opaque Texture and enable it. This provides the `_CameraOpaqueTexture` that replaces GrabPass.

2. **Render Feature Alternative**: For more advanced control, consider creating a custom Render Feature that captures the screen before transparent objects are rendered.

3. **Shader Graph Option**: For visual editing, you could recreate this effect using Shader Graph with the Scene Color node.

4. **Performance Considerations**: The three-pass approach in URP may have different performance characteristics than the original GrabPass implementation.

