### 1. **Development Environment Setup**
- Install **Node.js** (v18+), **npm**, **Git**, and an Ethereum client like **Geth** (Go Ethereum) or **Hyperledger Besu** (enterprise-grade). For forking, Besu is a good choice as it's Java-based and supports private networks.
- Clone the Ethereum repository: `git clone https://github.com/ethereum/go-ethereum.git` (for Geth) or `https://github.com/hyperledger/besu.git` (for Besu).

### 2. **Modify the Codebase**
- Changes typically involve parameters in the **chain configuration** (e.g., `chainparams.go` in Geth). Adjust:
  - `Block time`: Modify `TargetBlockTime`.
  - `Block reward`: Update `BlockReward` in the consensus algorithm.
  - `Total supply`: Adjust genesis allocation or monetary policy.
- Use an IDE like **VS Code** with Solidity extensions.

### 3. **Configure Genesis Block**
- Create a `genesis.json` file. Example for a private network:
```json
{
  "config": {
    "chainId": 12345,
    "homesteadBlock": 0,
    "eip150Block": 0,
    "eip155Block": 0,
    "eip158Block": 0
  },
  "difficulty": "0x400",
  "gasLimit": "0x8000000",
  "alloc": {
    "0xYourAddress": { "balance": "1000000000000000000000000" }
  }
}
```
- Initialize the network: `geth init genesis.json --datadir ./chaindata`.

### 4. **Build and Deploy Custom Network**
- Compile the modified client: `make geth` (for Geth) or `./gradlew build` (for Besu).
- Run a node: `geth --datadir ./chaindata --networkid 12345 --http --http.api eth,net,web3,personal`.
- Use **Ganache** or **Hardhat** for local testing.

### 5. **Create Cryptocurrency (ERC-20 Token)**
- Instead of modifying the base protocol, you can deploy a smart contract. Here's a simple ERC-20 contract in Solidity (as generated):
```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract SimpleToken {
    string public name = "Simple Token";
    string public symbol = "STK";
    uint8 public decimals = 18;
    uint256 public totalSupply = 1000000 * 10**uint256(decimals);

    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);

    constructor() {
        balanceOf[msg.sender] = totalSupply;
    }

    function transfer(address _to, uint256 _value) public returns (bool success) {
        require(_to != address(0), "Cannot transfer to zero address");
        require(balanceOf[msg.sender] >= _value, "Insufficient balance");

        balanceOf[msg.sender] -= _value;
        balanceOf[_to] += _value;
        emit Transfer(msg.sender, _to, _value);
        return true;
    }

    function approve(address _spender, uint256 _value) public returns (bool success) {
        allowance[msg.sender][_spender] = _value;
        emit Approval(msg.sender, _spender, _value);
        return true;
    }

    function transferFrom(address _from, address _to, uint256 _value) public returns (bool success) {
        require(_to != address(0), "Cannot transfer to zero address");
        require(balanceOf[_from] >= _value, "Insufficient balance");
        require(allowance[_from][msg.sender] >= _value, "Allowance exceeded");

        balanceOf[_from] -= _value;
        balanceOf[_to] += _value;
        allowance[_from][msg.sender] -= _value;
        emit Transfer(_from, _to, _value);
        return true;
    }

    function mint(uint256 _amount) public {
        balanceOf[msg.sender] += _amount;
        totalSupply += _amount;
        emit Transfer(address(0), msg.sender, _amount);
    }
}
```
- Deploy using **Remix IDE** or **Hardhat**.

### 6. **Develop a Wallet**
- Use **ethers.js** or **web3.js** for integration. Example with ethers.js:
```javascript
import { ethers } from 'ethers';

const TOKEN_ABI = [
  "function transfer(address to, uint256 value) returns (bool)",
  "function balanceOf(address owner) view returns (uint256)",
  "function mint(uint256 amount)"
];

async function connectWallet() {
  if (window.ethereum) {
    const provider = new ethers.providers.Web3Provider(window.ethereum);
    await provider.send("eth_requestAccounts", []);
    return provider.getSigner();
  }
  throw new Error("No wallet found");
}

async function sendTokens(toAddress, amount) {
  const signer = await connectWallet();
  const contract = new ethers.Contract(CONTRACT_ADDRESS, TOKEN_ABI, signer);

  const tx = await contract.transfer(toAddress, ethers.utils.parseEther(amount));
  await tx.wait();
  console.log("Transaction confirmed");
}

async function getBalance() {
  const signer = await connectWallet();
  const contract = new ethers.Contract(CONTRACT_ADDRESS, TOKEN_ABI, signer);
  const balance = await contract.balanceOf(await signer.getAddress());
  return ethers.utils.formatEther(balance);
}
