       auth
           .ldapAuthentication()
           .userDnPatterns("uid={0},ou=people")
           .groupSearchBase("ou=groups")
           .contextSource()
           .url("ldap://localhost:389/dc=example,dc=com")
           .and()
           .passwordCompare()
           .passwordEncoder(new BCryptPasswordEncoder())
           .passwordAttribute("userPassword");
