```typescript
import { ResultType, StepResponse } from '@txp-core/runtime';
import { Effect, put } from 'redux-saga/effects';
import {
    PaymentChargesTableAction,
    paymentTableSelectors
} from '@txp-core/payment-transactions-table';
import { cloneDeep, select } from '@txp-core/basic-utils';
import { CreditChargesPaymentTypes } from '@txp-core/payment-transactions-table/dist/paymentTableStateTypes';

export function* outstandingTransactionsHandler(): Generator<Effect, StepResponse, string> {
    const creditTableLines = yield* select(paymentTableSelectors.getCredits);
    const totalOfChargesTable = yield* select(paymentTableSelectors.getTotalOfChargesTable);

    // Initialize credit table with deep copy
    const updateCreditTable: CreditChargesPaymentTypes[] = cloneDeep(creditTableLines) || [];

    // Filter credits that have linked payment amounts
    const filterCheckedCredit = updateCreditTable.filter(
        (payment) => payment.linkedPaymentAmount !== ''
    );

    let remainingAmount = totalOfChargesTable;

    // Process each credit to allocate payment amounts
    const updateFilterCheckedCredit = filterCheckedCredit.map((credit) => {
        const amountToAllocate = Math.min(remainingAmount, credit.openBalance);

        if (amountToAllocate > 0) {
            credit.linkedPaymentAmount = amountToAllocate.toString();
            remainingAmount -= amountToAllocate;
        } else {
            credit.linkedPaymentAmount = '';
        }

        return credit;
    });

    // Merge updated credits back into original table
    const updatedCreditTable = updateCreditTable.map((credit) => {
        const updatedCredit = updateFilterCheckedCredit.find((c) => c.txnId === credit.txnId);
        return updatedCredit ? { ...credit, ...updatedCredit } : credit;
    });

    yield put(PaymentChargesTableAction.fullCreditsTableUpdate(updatedCreditTable));

    return { result: ResultType.SUCCESS };
}
```

