Here's a JavaScript implementation of a pulsing animation similar to medical cardio device displays. The dot moves left to right continuously along a line, and at regular intervals (with slight randomness) it pulses with a triangle waveform (height increases linearly then decreases linearly) while still moving horizontally.

```html
<!DOCTYPE html>
<html>
<head>
<style>
.pulse-animation {
  width: 100%;
  height: 32px;
  position: relative;
  overflow: hidden;
  background: #000;
}

.pulse-line {
  position: absolute;
  top: 50%;
  left: 0;
  width: 100%;
  height: 1px;
  background-color: #00ff00;
}

.pulse-dot {
  position: absolute;
  top: 50%;
  left: 0;
  width: 8px;
  height: 8px;
  background-color: #00ff00;
  border-radius: 50%;
  transform: translateY(-50%);
  transform-origin: center center;
}
</style>
</head>
<body>
<div class="pulse-animation">
  <div class="pulse-line"></div>
  <div class="pulse-dot"></div>
</div>

<script>
(function() {
  const container = document.querySelector('.pulse-animation');
  const dot = document.querySelector('.pulse-dot');
  const line = document.querySelector('.pulse-line');
  const dotWidth = 8;
  const containerWidth = container.offsetWidth;
  let position = -dotWidth; // start off left edge
  let pulseStartTime = null;
  let pulseDuration = 1000; // total pulse duration in ms (increase + decrease)
  let pulseInterval = 2000; // base interval between pulses
  let nextPulseTime = Date.now() + pulseInterval;
  let animId = null;

  function triangleWave(elapsed, halfDuration) {
    // elapsed: time since pulse start (0 to pulseDuration)
    // halfDuration = pulseDuration / 2
    if (elapsed < halfDuration) {
      return elapsed / halfDuration; // linear increase from 0 to 1
    } else {
      return 1 - (elapsed - halfDuration) / halfDuration; // linear decrease from 1 to 0
    }
  }

  function animate() {
    const now = Date.now();
    // Move dot horizontally
    position += 1;
    if (position > containerWidth) {
      position = -dotWidth;
    }
    dot.style.left = position + 'px';

    // Handle pulsing
    if (pulseStartTime !== null) {
      const elapsed = now - pulseStartTime;
      if (elapsed < pulseDuration) {
        const half = pulseDuration / 2;
        const factor = triangleWave(elapsed, half);
        const scaleY = 1 + factor * 3; // from 1 to 4 (8px to 32px)
        dot.style.transform = `translateY(-50%) scaleY(${scaleY})`;
      } else {
        // Pulse finished
        pulseStartTime = null;
        dot.style.transform = 'translateY(-50%) scaleY(1)';
      }
    } else {
      // Check if it's time to start a new pulse
      if (now >= nextPulseTime) {
        pulseStartTime = now;
        // Schedule next pulse with some randomness (±500ms)
        nextPulseTime = now + pulseInterval + (Math.random() * 1000 - 500);
      }
    }

    animId = requestAnimationFrame(animate);
  }

  // Start animation
  animate();

  // Optional: handle window resize
  window.addEventListener('resize', function() {
    // Recalculate container width
    // (if you want the dot to reset, you can adjust position)
  });
})();
</script>
</body>
</html>
```

**Key features:**
- Smooth horizontal movement using `requestAnimationFrame`.
- Triangle waveform pulse: height increases linearly from 8px to 32px over 500ms, then decreases linearly back to 8px over 500ms.
- Pulses occur approximately every 2 seconds with ±500ms randomness.
- The dot remains centered on the line during scaling (`transform-origin: center center`).
- The line is a thin green line across the full width, and the dot is a green circle.

You can adjust `pulseDuration`, `pulseInterval`, and the scaling factor to match your desired visual effect.

