                // Create dimensions for each hole
                CreateCartesianDimensions(plate, holes, origin);

                Autodesk.AutoCAD.ApplicationServices.Application.ShowAlertDialog($"Successfully dimensioned {holes.Count} holes.");
            }
            catch (Exception ex)
            {
