        /// <summary>
        /// Get selected plate from document (simplified - you may need to implement proper selection)
        /// </summary>
        private static Plate GetSelectedPlate(Document doc)
        {
            // This is a simplified implementation
            // In practice, you would use selection sets or other methods to get the plate
            using (Transaction tr = new Transaction())
            {
                tr.Start();

                // Example: Get first plate in model space
