                foreach (DBObject obj in doc.Database.GetModelSpace())
                {
                    if (obj is Plate plate)
                    {
                        return plate;
                    }
                }

                tr.Commit();
            }
            return null;
        }

        /// <summary>
        /// Extract all holes from a plate
        /// </summary>
        private static List<Hole> GetHolesFromPlate(Plate plate)
        {
            List<Hole> holes = new List<Hole>();

            // Get features attached to the plate
            var features = plate.GetFeatures();
            foreach (var feature in features)
            {
                if (feature is Hole hole)
                {
                    holes.Add(hole);
                }
                // Also check for hole features in other feature types
                else if (feature is FeaturePattern pattern)
