                        if (patternFeature is Hole patternHole)
                        {
                            holes.Add(patternHole);
                        }
                    }
                }
            }

            return holes;
        }

        /// <summary>
        /// Calculate bottom-left corner of plate as origin (0,0)
        /// </summary>
        private static Point3d CalculatePlateOrigin(Plate plate)
        {
            // Get plate bounding box
            BoundingBox3d bbox = plate.GetBoundingBox();

            // Use minimum X and Y as origin (bottom-left corner)
            // Z coordinate is typically 0 for 2D dimensions
            return new Point3d(bbox.MinPoint.X, bbox.MinPoint.Y, 0);
        }

        /// <summary>
        /// Create Cartesian X and Y dimensions for each hole
        /// </summary>
        private static void CreateCartesianDimensions(Plate plate, List<Hole> holes, Point3d origin)
        {
            using (Transaction tr = new Transaction())
            {
                tr.Start();

                // Get current drawing or create new one
                // Note: You may need to access the drawing differently based on your setup
                Drawing drawing = GetCurrentDrawing();

                double dimensionOffset = 10.0; // Offset for dimension text

                foreach (Hole hole in holes)
