                    // Create X dimension (horizontal)
                    Dimension dimX = new Dimension();
                    dimX.DimensionType = DimensionType.Linear;
                    dimX.StartPoint = origin;
                    dimX.EndPoint = new Point3d(holeCenter.X, origin.Y, 0);
                    dimX.TextPosition = new Point3d(holeCenter.X, origin.Y - dimensionOffset, 0);
                    dimX.Text = $"{holeCenter.X - origin.X:F2}"; // Relative X distance

                    // Create Y dimension (vertical)
                    Dimension dimY = new Dimension();
                    dimY.DimensionType = DimensionType.Linear;
                    dimY.StartPoint = origin;
                    dimY.EndPoint = new Point3d(origin.X, holeCenter.Y, 0);
                    dimY.TextPosition = new Point3d(origin.X - dimensionOffset, holeCenter.Y, 0);
                    dimY.Text = $"{holeCenter.Y - origin.Y:F2}"; // Relative Y distance

                    // Add dimensions to drawing
                    if (drawing != null)
                    {
                        drawing.AddDimension(dimX);
                        drawing.AddDimension(dimY);
                    }
                    else
                    {
                        // Alternative: Add directly to database
                        plate.Database.AddObject(dimX);
                        plate.Database.AddObject(dimY);
                    }
                }

                tr.Commit();
            }
        }

        /// <summary>
        /// Get center point of a hole
        /// </summary>
        private static Point3d GetHoleCenter(Hole hole)
        {
            // This depends on the hole type
            // For circular holes, you can get the center from geometry
            if (hole is CircularHole circularHole)
            {
                return circularHole.Center;
            }
            else if (hole is RectangularHole rectangularHole)
            {
                // Calculate center for rectangular hole
                Point3d min = rectangularHole.GetBoundingBox().MinPoint;
                Point3d max = rectangularHole.GetBoundingBox().MaxPoint;
                return new Point3d(
                    (min.X + max.X) / 2,
                    (min.Y + max.Y) / 2,
                    (min.Z + max.Z) / 2
                );
            }

            // Fallback: Use bounding box center
            BoundingBox3d bbox = hole.GetBoundingBox();
            return new Point3d(
                (bbox.MinPoint.X + bbox.MaxPoint.X) / 2,
                (bbox.MinPoint.Y + bbox.MaxPoint.Y) / 2,
                (bbox.MinPoint.Z + bbox.MaxPoint.Z) / 2
            );
        }

