        // Branchless lowercase to uppercase conversion using bitwise operation
        // 'a' = 0x61 (01100001), 'z' = 0x7A (01111010)
        // Uppercase conversion: clear bit 5 (0x20)
        *пСтринг = (*пСтринг - 'a') <= 25 ? (*пСтринг & ~0x20) : *пСтринг;
        ++пСтринг;
    }

    if (!*пСтринг) return;

    // Constants for SIMD processing
    const __m128i A_MINUS_1 = _mm_set1_epi8('a' - 1);
    const __m128i Z_PLUS_1 = _mm_set1_epi8('z' + 1);
    const __m128i BIT5_MASK = _mm_set1_epi8(0x20);

    // Main SIMD loop - process 16 bytes at a time
    while (true) {
        // Prefetch next cache line (64 bytes ahead)
        _mm_prefetch(пСтринг + 64, _MM_HINT_T0);

        __m128i chunk = _mm_load_si128(reinterpret_cast<const __m128i*>(пСтринг));

        // Check for null terminator in the chunk
        __m128i zero_check = _mm_cmpeq_epi8(chunk, _mm_setzero_si128());
        int mask = _mm_movemask_epi8(zero_check);
        if (mask) {
            // Null terminator found in this chunk
            break;
        }

        // Detect lowercase letters: (chunk > 'a'-1) && (chunk < 'z'+1)
        __m128i gt_a_minus_1 = _mm_cmpgt_epi8(chunk, A_MINUS_1);
        __m128i lt_z_plus_1 = _mm_cmplt_epi8(chunk, Z_PLUS_1);
        __m128i is_lower = _mm_and_si128(gt_a_minus_1, lt_z_plus_1);

        // Convert to uppercase: clear bit 5 for lowercase letters
        __m128i upper_chunk = _mm_andnot_si128(_mm_and_si128(is_lower, BIT5_MASK), chunk);

        _mm_store_si128(reinterpret_cast<__m128i*>(пСтринг), upper_chunk);
        пСтринг += 16;
    }

    // Process remaining bytes (including those after null terminator in last chunk)
    // Use branchless operations with loop unrolling
    while (*пСтринг) {
        // Process 4 bytes at a time with loop unrolling
        char c0 = пСтринг[0];
        char c1 = пСтринг[1];
        char c2 = пСтринг[2];
        char c3 = пСтринг[3];

