## Main Plugin Class (BountyPlugin.java)
```java
package com.example.bounty;

import net.milkbowl.vault.economy.Economy;
import org.bukkit.Bukkit;
import org.bukkit.World;
import org.bukkit.configuration.file.FileConfiguration;
import org.bukkit.entity.Player;
import org.bukkit.plugin.RegisteredServiceProvider;
import org.bukkit.plugin.java.JavaPlugin;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

public class BountyPlugin extends JavaPlugin {
    private static BountyPlugin instance;
    private Economy economy;
    private Set<String> allowedWorlds;
    private final Map<UUID, Double> bounties = new ConcurrentHashMap<>();

    @Override
    public void onEnable() {
        instance = this;
        saveDefaultConfig();
        setupEconomy();
        loadAllowedWorlds();
        loadBounties();

        getCommand("bounty").setExecutor(new BountyCommand(this));
        getServer().getPluginManager().registerEvents(new DeathListener(this), this);

        getLogger().info("Bounty Plugin enabled!");
    }

    @Override
    public void onDisable() {
        saveBounties();
        getLogger().info("Bounty Plugin disabled!");
    }

    private void setupEconomy() {
        if (getServer().getPluginManager().isPluginEnabled("Vault")) {
            RegisteredServiceProvider<Economy> rsp = getServer().getServicesManager().getRegistration(Economy.class);
            if (rsp != null) {
                economy = rsp.getProvider();
                getLogger().info("Vault economy hooked: " + economy.getName());
            } else {
                getLogger().warning("Vault economy not found!");
            }
        } else {
            getLogger().warning("Vault not found! Economy features disabled.");
        }
    }

    private void loadAllowedWorlds() {
        allowedWorlds = new HashSet<>(getConfig().getStringList("allowed-worlds"));
        getLogger().info("Loaded " + allowedWorlds.size() + " allowed worlds");
    }

    private void loadBounties() {
        bounties.clear();
        FileConfiguration config = getConfig();
        if (config.contains("bounties")) {
            for (String key : config.getConfigurationSection("bounties").getKeys(false)) {
                try {
                    UUID uuid = UUID.fromString(key);
                    double amount = config.getDouble("bounties." + key);
                    if (amount > 0) {
                        bounties.put(uuid, amount);
                    }
                } catch (IllegalArgumentException e) {
                    getLogger().warning("Invalid UUID in bounties: " + key);
                }
            }
        }
    }

    private void saveBounties() {
        FileConfiguration config = getConfig();
        config.set("bounties", null);
        for (Map.Entry<UUID, Double> entry : bounties.entrySet()) {
            if (entry.getValue() > 0) {
                config.set("bounties." + entry.getKey().toString(), entry.getValue());
            }
        }
        saveConfig();
    }

    public void reloadPluginConfig() {
        reloadConfig();
        loadAllowedWorlds();
        loadBounties();
    }

    public static BountyPlugin getInstance() { return instance; }
    public Economy getEconomy() { return economy; }
    public Set<String> getAllowedWorlds() { return allowedWorlds; }
    public Map<UUID, Double> getBounties() { return bounties; }

    public double getBounty(UUID playerId) {
        return bounties.getOrDefault(playerId, 0.0);
    }

    public void addBounty(UUID playerId, double amount) {
        bounties.put(playerId, bounties.getOrDefault(playerId, 0.0) + amount);
    }

    public void resetBounty(UUID playerId) {
        bounties.remove(playerId);
    }

    public boolean isWorldAllowed(World world) {
        return allowedWorlds.contains(world.getName());
    }
}
```

## Command Executor (BountyCommand.java)
```java
package com.example.bounty;

import org.bukkit.Bukkit;
import org.bukkit.ChatColor;
import org.bukkit.OfflinePlayer;
import org.bukkit.command.Command;
import org.bukkit.command.CommandExecutor;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;

import java.util.Map;
import java.util.UUID;

public class BountyCommand implements CommandExecutor {
    private final BountyPlugin plugin;

    public BountyCommand(BountyPlugin plugin) {
        this.plugin = plugin;
    }

    @Override
    public boolean onCommand(CommandSender sender, Command cmd, String label, String[] args) {
        if (args.length == 0) {
            sendUsage(sender);
            return true;
        }

        if (sender instanceof Player) {
            Player player = (Player) sender;
            if (!plugin.isWorldAllowed(player.getWorld())) {
                player.sendMessage(ChatColor.RED + "Bounties are not allowed in this world!");
                return true;
            }
        }

        switch (args[0].toLowerCase()) {
            case "add":
                return handleAdd(sender, args);
            case "list":
                return handleList(sender);
            case "reload":
                return handleReload(sender);
            default:
                return handleShow(sender, args[0]);
        }
    }

    private boolean handleAdd(CommandSender sender, String[] args) {
        if (!(sender instanceof Player)) {
            sender.sendMessage(ChatColor.RED + "Only players can add bounties!");
            return true;
        }

        if (args.length < 3) {
            sender.sendMessage(ChatColor.RED + "Usage: /bounty add <player> <amount>");
            return true;
        }

        Player player = (Player) sender;
        String targetName = args[1];
        OfflinePlayer target = Bukkit.getOfflinePlayer(targetName);

        if (target == null || (!target.hasPlayedBefore() && !target.isOnline())) {
            player.sendMessage(ChatColor.RED + "Player not found!");
            return true;
        }

        if (target.getUniqueId().equals(player.getUniqueId())) {
            player.sendMessage(ChatColor.RED + "You cannot place a bounty on yourself!");
            return true;
        }

        double amount;
        try {
            amount = Double.parseDouble(args[2]);
        } catch (NumberFormatException e) {
            player.sendMessage(ChatColor.RED + "Invalid amount!");
            return true;
        }

        if (amount <= 0) {
            player.sendMessage(ChatColor.RED + "Amount must be positive!");
            return true;
        }

        Economy economy = plugin.getEconomy();
        if (economy == null) {
            player.sendMessage(ChatColor.RED + "Economy system not available!");
            return true;
        }

        if (economy.getBalance(player) < amount) {
            player.sendMessage(ChatColor.RED + "You don't have enough money!");
            return true;
        }

        economy.withdrawPlayer(player, amount);
        plugin.addBounty(target.getUniqueId(), amount);

        player.sendMessage(ChatColor.GREEN + "Added " + ChatColor.GOLD + "$" + amount + 
                          ChatColor.GREEN + " to bounty on " + ChatColor.YELLOW + target.getName());

        if (target.isOnline()) {
            target.getPlayer().sendMessage(ChatColor.YELLOW + player.getName() + 
                                          ChatColor.RED + " has placed a $" + amount + 
                                          " bounty on you!");
        }

        return true;
    }

    private boolean handleShow(CommandSender sender, String playerName) {
        OfflinePlayer target = Bukkit.getOfflinePlayer(playerName);
        if (target == null || (!target.hasPlayedBefore() && !target.isOnline())) {
            sender.sendMessage(ChatColor.RED + "Player not found!");
            return true;
        }

        double bounty = plugin.getBounty(target.getUniqueId());
        sender.sendMessage(ChatColor.GOLD + "Bounty on " + ChatColor.YELLOW + target.getName() + 
                          ChatColor.GOLD + ": " + ChatColor.GREEN + "$" + bounty);
        return true;
    }

    private boolean handleList(CommandSender sender) {
        Map<UUID, Double> bounties = plugin.getBounties();
        if (bounties.isEmpty()) {
            sender.sendMessage(ChatColor.YELLOW + "No active bounties!");
            return true;
        }

        sender.sendMessage(ChatColor.GOLD + "=== Active Bounties ===");
        for (Map.Entry<UUID, Double> entry : bounties.entrySet()) {
            OfflinePlayer player = Bukkit.getOfflinePlayer(entry.getKey());
            String name = player.getName() != null ? player.getName() : "Unknown";
            sender.sendMessage(ChatColor.YELLOW + name + ChatColor.GOLD + ": " + 
                              ChatColor.GREEN + "$" + entry.getValue());
        }
        return true;
    }

    private boolean handleReload(CommandSender sender) {
        if (!sender.hasPermission("bounty.admin")) {
            sender.sendMessage(ChatColor.RED + "You don't have permission!");
            return true;
        }

        plugin.reloadPluginConfig();
        sender.sendMessage(ChatColor.GREEN + "Bounty configuration reloaded!");
        return true;
    }

    private void sendUsage(CommandSender sender) {
        sender.sendMessage(ChatColor.GOLD + "=== Bounty Commands ===");
        sender.sendMessage(ChatColor.YELLOW + "/bounty <player> " + ChatColor.GRAY + "- Show bounty amount");
        sender.sendMessage(ChatColor.YELLOW + "/bounty add <player> <amount> " + ChatColor.GRAY + "- Add to bounty");
        sender.sendMessage(ChatColor.YELLOW + "/bounty list " + ChatColor.GRAY + "- List all active bounties");
        if (sender.hasPermission("bounty.admin")) {
            sender.sendMessage(ChatColor.YELLOW + "/bounty reload " + ChatColor.GRAY + "- Reload configuration");
        }
    }
}
```

## Death Listener (DeathListener.java)
```java
package com.example.bounty;

import net.milkbowl.vault.economy.Economy;
import org.bukkit.ChatColor;
import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.Listener;
import org.bukkit.event.entity.PlayerDeathEvent;

public class DeathListener implements Listener {
    private final BountyPlugin plugin;

    public DeathListener(BountyPlugin plugin) {
        this.plugin = plugin;
    }

    @EventHandler
    public void onPlayerDeath(PlayerDeathEvent event) {
        Player victim = event.getEntity();
        Player killer = victim.getKiller();

        if (killer == null) return;
        if (!plugin.isWorldAllowed(victim.getWorld())) return;

        double bounty = plugin.getBounty(victim.getUniqueId());
        if (bounty <= 0) return;

        Economy economy = plugin.getEconomy();
        if (economy != null) {
            economy.depositPlayer(killer, bounty);
            killer.sendMessage(ChatColor.GREEN + "You received " + ChatColor.GOLD + "$" + bounty + 
                             ChatColor.GREEN + " from killing " + ChatColor.YELLOW + victim.getName());

            event.getDrops().forEach(item -> {
                if (Math.random() < 0.1) { // 10% chance to drop bounty notice
                    killer.getWorld().dropItemNaturally(victim.getLocation(), item);
                }
            });
        }

        plugin.resetBounty(victim.getUniqueId());
        victim.sendMessage(ChatColor.RED + "Your bounty has been collected!");

        // Broadcast to server
        plugin.getServer().broadcastMessage(ChatColor.GOLD + killer.getName() + 
                                          ChatColor.GREEN + " has collected a $" + bounty + 
                                          " bounty on " + ChatColor.YELLOW + victim.getName() + "!");
    }
}
```

