        int port = 22;
        String cmd = "python /path/to/script.py";

        executeSSHCommand(ip, port, cmd);
    }
});

// Cleanup executor in onDestroy
@Override
protected void onDestroy() {
    super.onDestroy();
    if (executor != null && !executor.isShutdown()) {
        executor.shutdown();
